#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
    int pipefd[2];
    if (pipe(pipefd) == -1) {
        std::cerr << "Pipe failed" << std::endl;
        return 1;
    }

    pid_t pid = fork();
    if (pid == -1) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    }

    if (pid == 0) { // Child process
        // Close unnecessary file descriptors
        close(pipefd[1]); // Close write end in child

        // Redirect stdin and stdout to the pipe
        dup2(pipefd[0], STDIN_FILENO);  // Redirect stdin
        dup2(pipefd[0], STDOUT_FILENO); // Redirect stdout

        // Close the pipe file descriptor
        close(pipefd[0]);

        // Execute some command (for example, pass the pipe to less)
        execlp("less", "less", NULL);
        std::cerr << "Exec failed" << std::endl;
        _exit(1);
    } else { // Parent process
        close(pipefd[0]); // Close unnecessary file descriptors in parent

        // Write something to the pipe
        const char* message = "Hello from parent process";
        write(pipefd[1], message, strlen(message) + 1);

        close(pipefd[1]);

        // Wait for the child to finish
        wait(NULL);
    }

    return 0;
}
```

This code creates a pipe, forks a new process, and then redirects the child process's standard input and output to the read and write ends of the pipe, respectively. The parent process writes a message to the pipe, and the child process reads from the pipe and passes the message to the `less` command.
